    }
    foreach (var ctor in type.GetConstructors())
    {
        Console.WriteLine($"  [ctor] ({string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
    Console.WriteLine();
}
EOF
