using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent;

/// <summary>
/// Provides web search and page-reading tools for the research agent.
/// Uses DuckDuckGo HTML search (no API key required).
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a topic. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            using var response = await _httpClient.SendAsync(
                request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and read the text content of a web page at the given URL. " +
                 "Returns the extracted text content (up to 4000 characters).")]
    public async Task<string> ReadWebPage(
        [Description("The full URL of the web page to read")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            if (!Uri.TryCreate(url, UriKind.Absolute, out var uri)
                || (uri.Scheme != "http" && uri.Scheme != "https"))
            {
                return "Invalid URL. Please provide a valid http or https URL.";
            }

            using var request = new HttpRequestMessage(HttpMethod.Get, uri);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            using var response = await _httpClient.SendAsync(
                request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = ExtractTextFromHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract meaningful text from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to read page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new List<string>();
        var resultPattern = ResultRegex();

        foreach (Match match in resultPattern.Matches(html))
        {
            var resultHtml = match.Value;

            var titleMatch = TitleRegex().Match(resultHtml);
            var snippetMatch = SnippetRegex().Match(resultHtml);

            var title = titleMatch.Success
                ? StripHtmlTags(WebUtility.HtmlDecode(titleMatch.Groups[2].Value)).Trim()
                : "No title";
            var href = titleMatch.Success
                ? WebUtility.HtmlDecode(titleMatch.Groups[1].Value)
                : "";
            var snippet = snippetMatch.Success
                ? StripHtmlTags(WebUtility.HtmlDecode(snippetMatch.Groups[1].Value)).Trim()
                : "No snippet";

            // DuckDuckGo wraps actual URLs in a redirect; extract the real URL.
            var realUrl = ExtractRealUrl(href);

            results.Add($"Title: {title}\nURL: {realUrl}\nSnippet: {snippet}\n");

            if (results.Count >= 5)
                break;
        }

        return results.Count > 0
            ? $"Found {results.Count} results:\n\n{string.Join("\n---\n", results)}"
            : "No search results found. Try rephrasing the query.";
    }

    private static string ExtractRealUrl(string duckDuckGoUrl)
    {
        if (string.IsNullOrEmpty(duckDuckGoUrl))
            return "";

        // DDG lite wraps URLs like //duckduckgo.com/l/?uddg=<encoded_url>&...
        var uddgMatch = UddgRegex().Match(duckDuckGoUrl);
        if (uddgMatch.Success)
            return Uri.UnescapeDataString(uddgMatch.Groups[1].Value);

        return duckDuckGoUrl.StartsWith("//")
            ? "https:" + duckDuckGoUrl
            : duckDuckGoUrl;
    }

    private static string ExtractTextFromHtml(string html)
    {
        // Remove script and style blocks
        var cleaned = ScriptStyleRegex().Replace(html, " ");
        // Strip all HTML tags
        cleaned = StripHtmlTags(cleaned);
        // Collapse whitespace
        cleaned = WhitespaceRegex().Replace(cleaned, " ").Trim();
        return WebUtility.HtmlDecode(cleaned);
    }

    private static string StripHtmlTags(string html) =>
        TagRegex().Replace(html, "");

    [GeneratedRegex(@"<result[\s>].*?</result>|class=""result[\s""].*?(?=class=""result|$)",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultRegex();

    [GeneratedRegex(@"<a[^>]+href=""([^""]+)""[^>]*class=""result__a""[^>]*>(.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex TitleRegex();

    [GeneratedRegex(@"class=""result__snippet""[^>]*>(.*?)</(?:td|a|div|span)>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetRegex();

    [GeneratedRegex(@"uddg=([^&]+)")]
    private static partial Regex UddgRegex();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStyleRegex();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespaceRegex();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagRegex();
}

