using System.ComponentModel;
using System.Text;

namespace ResearchAgent;

/// <summary>
/// Provides note-taking tools for the research agent to organize findings.
/// Stores notes in memory for the duration of the session.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. " +
                 "Use this to record key findings, facts, or insights discovered during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        var note = new Note(title, content, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Use this to review what has been gathered so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No research notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== {_notes.Count} Research Notes ===");

        for (var i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine();
            sb.AppendLine($"--- Note #{i + 1}: {note.Title} ---");
            sb.AppendLine($"Saved at: {note.Timestamp:u}");
            sb.AppendLine(note.Content);
        }

        return sb.ToString();
    }

    [Description("Delete a research note by its number (1-based). " +
                 "Use this to remove notes that are no longer relevant.")]
    public string DeleteNote(
        [Description("The note number to delete (1-based)")] int noteNumber)
    {
        if (noteNumber < 1 || noteNumber > _notes.Count)
            return $"Invalid note number. There are {_notes.Count} notes (1-{_notes.Count}).";

        var removed = _notes[noteNumber - 1];
        _notes.RemoveAt(noteNumber - 1);
        return $"Deleted note: \"{removed.Title}\"";
    }

    private sealed record Note(string Title, string Content, DateTime Timestamp);
}

