using System.ClientModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent;

// ── Configuration ──────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

const string modelId = "gpt-4o-mini-2024-07-18";

// ── Service setup ──────────────────────────────────────────────────────
var services = new ServiceCollection();

services.AddLogging(b => b
    .AddConsole()
    .SetMinimumLevel(LogLevel.Warning));

services.AddHttpClient<WebSearchTool>(client =>
    client.Timeout = TimeSpan.FromSeconds(15));

services.AddSingleton<NoteTool>();

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAIClient(
        new ApiKeyCredential(apiKey))));

var sp = services.BuildServiceProvider();

// ── Tools ──────────────────────────────────────────────────────────────
var webSearchTool = sp.GetRequiredService<WebSearchTool>();
var noteTool = sp.GetRequiredService<NoteTool>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearchTool.SearchWeb,
        nameof(webSearchTool.SearchWeb),
        "Search the web for information on a topic"),
    AIFunctionFactory.Create(webSearchTool.ReadWebPage,
        nameof(webSearchTool.ReadWebPage),
        "Fetch and read the text content of a web page"),
    AIFunctionFactory.Create(noteTool.SaveNote,
        nameof(noteTool.SaveNote),
        "Save a research note with a title and content"),
    AIFunctionFactory.Create(noteTool.GetNotes,
        nameof(noteTool.GetNotes),
        "Retrieve all saved research notes"),
    AIFunctionFactory.Create(noteTool.DeleteNote,
        nameof(noteTool.DeleteNote),
        "Delete a research note by its number"),
};

// ── Agent ──────────────────────────────────────────────────────────────
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic
    the user provides and produce a well-organized summary of your findings.

    Follow this research process:
    1. Search the web for the topic using multiple relevant queries.
    2. Read promising web pages to gather detailed information.
    3. Save key findings as notes using the note-taking tool.
    4. After gathering enough information, review your notes and produce
       a comprehensive summary with sections, key facts, and sources.

    Guidelines:
    - Use at least 2-3 different search queries to cover the topic broadly.
    - Save notes as you go so you don't lose information.
    - Always cite your sources with URLs.
    - Be factual and objective in your summary.
    """;

var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

var agent = new ChatClientAgent(
    chatClient,
    instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking",
    tools: tools,
    loggerFactory: loggerFactory,
    services: sp);

// ── Interactive loop ───────────────────────────────────────────────────
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════════════╗");
Console.WriteLine("║         🔍  Research Agent  🔍              ║");
Console.WriteLine("║  Enter a topic to research, or 'quit' to    ║");
Console.WriteLine("║  exit.                                      ║");
Console.WriteLine("╚══════════════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

var session = await agent.CreateSessionAsync("research-session");
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

while (true)
{
    Console.ForegroundColor = ConsoleColor.Green;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic))
        continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching... (the agent will search the web and take notes)\n");
    Console.ResetColor();

    try
    {
        await foreach (var update in agent.RunStreamingAsync(
            $"Research this topic and provide a comprehensive summary: {topic}",
            session,
            runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}");
        Console.ResetColor();
    }
}

